let topicParts = msg.topic.split('/');
let zona = topicParts[1]; 
let telemetria = msg.payload;

let estadoZonas = flow.get('estadoZonas') || {};

if (!estadoZonas[zona]) {
    estadoZonas[zona] = {
        leituras_ch4: {},
        leituras_co: {}
    };
}

if (telemetria.tipo_dado === 'CH4') {
    estadoZonas[zona].leituras_ch4[telemetria.sensor_id] = telemetria.valor;
} else if (telemetria.tipo_dado === 'CO') {
    estadoZonas[zona].leituras_co[telemetria.sensor_id] = telemetria.valor;
}

let valoresCH4 = Object.values(estadoZonas[zona].leituras_ch4);
let mediaCH4 = 0;

if (valoresCH4.length > 0) {
    let soma = valoresCH4.reduce((acc, val) => acc + val, 0);
    mediaCH4 = soma / valoresCH4.length;
}

let statusVentilacao = "DESLIGADO";
if (mediaCH4 >= 1.0) {
    statusVentilacao = "LIGADO_100% - ALERTA VERMELHO";
} else if (mediaCH4 >= 0.5) {
    statusVentilacao = "LIGADO_50% - ALERTA AMARELO";
} else {
    statusVentilacao = "MODO_ECONOMIA - VENTILACAO MINIMA";
}

flow.set('estadoZonas', estadoZonas);

msg.payload = {
    "actionType": "append",
    "entities": [
        {
            "id": `urn:ngsi-ld:ZonaMineracao:${zona}`,
            "type": "ZonaMineracao",
            "media_ch4": { "type": "Float", "value": parseFloat(mediaCH4.toFixed(2)) },
            "status_ventilacao": { "type": "Text", "value": statusVentilacao },
            "data_atualizacao": {
                "type": "DateTime",
                "value": new Date().toISOString()
            }
        }
    ]
};

msg.headers = {
    "Content-Type": "application/json"
};

return msg;
